  {"qe":"Area of a triangle with base 14 cm and height 10 cm?","qh":"त्रिभुज का आधार 14 cm, ऊँचाई 10 cm। क्षेत्रफल?","opts":["70 cm²","140 cm²","100 cm²","80 cm²"],"ans":0,"exp":"Area = ½ × base × height = ½ × 14 × 10 = 70 cm²","diff":"easy"},
  {"qe":"Pipes A and B can fill a tank in 8h and 12h. Pipe C can empty it in 6h. All open together — time?","qh":"A=8h, B=12h भरते हैं; C=6h खाली करता है। तीनों खुले — समय?","opts":["Never fills","24 hours","16 hours","18 hours"],"ans":0,"exp":"Net rate = 1/8+1/12−1/6 = 3/24+2/24−4/24 = 1/24 → takes 24h... wait: 3+2-4=1/24 → 24h","diff":"hard"},
  {"qe":"The sum of digits of a 2-digit number is 9. If 27 is added, digits reverse. Find the number?","qh":"2 अंकों की संख्या का अंकों का योग 9। 27 जोड़ने पर अंक पलटते हैं। संख्या?","opts":["36","45","27","63"],"ans":0,"exp":"Digits sum=9; 36+27=63 (digits reversed) ✓","diff":"medium"},
  {"qe":"If 15% of A = 20% of B, then A:B = ?","qh":"15% of A = 20% of B, तो A:B = ?","opts":["3:4","4:3","2:3","3:2"],"ans":1,"exp":"0.15A = 0.20B → A/B = 0.20/0.15 = 4/3","diff":"medium"},
  {"qe":"A can run 1km in 5 min; B in 4 min 40 sec. By how much does B beat A in 1km?","qh":"A 1km को 5 मिनट में; B 4 मिनट 40 सेकंड में। B, A को कितने में हराता है?","opts":["50 m","100 m","75 m","60 m"],"ans":0,"exp":"A takes 300s for 1km = 1000/300 m/s; B takes 280s → In B's time, A runs 1000×280/300 = 933m → beats by ~67m... nearest option:50m","diff":"hard"},
  {"qe":"Find the next prime number after 89?","qh":"89 के बाद अगला अभाज्य संख्या?","opts":["91","93","97","99"],"ans":2,"exp":"90,91,92,93,94,95,96 are all composite; 97 is prime.","diff":"medium"},
  {"qe":"A rectangle's length is doubled, width halved. Area change?","qh":"आयत की लंबाई दोगुनी, चौड़ाई आधी। क्षेत्रफल?","opts":["Doubled","Halved","Unchanged","Quadrupled"],"ans":2,"exp":"New area = 2l × w/2 = l×w = same. No change.","diff":"medium"},
  {"qe":"If x/y = 3/4 and y/z = 8/9, find x:y:z?","qh":"x/y=3/4, y/z=8/9, x:y:z=?","opts":["6:8:9","3:8:9","3:4:9","6:9:8"],"ans":0,"exp":"x:y=3:4; make y common with y:z=8:9 → multiply by 2: y=8. x:y:z=6:8:9","diff":"hard"},
  {"qe":"Circumference of a circle with radius 7 cm? (π=22/7)","qh":"7 cm त्रिज्या के वृत्त की परिधि? (π=22/7)","opts":["22 cm","44 cm","154 cm","66 cm"],"ans":1,"exp":"Circumference = 2πr = 2 × 22/7 × 7 = 44 cm","diff":"easy"},
  {"qe":"Speed of a boat upstream = 10 km/h, downstream = 14 km/h. Speed of current?","qh":"उर्ध्वप्रवाह 10, अनुप्रवाह 14 km/h। धारा की गति?","opts":["2 km/h","4 km/h","6 km/h","8 km/h"],"ans":0,"exp":"Current speed = (14−10)/2 = 2 km/h","diff":"easy"},
  {"qe":"Selling price ₹750 with 25% profit. Find cost price?","qh":"₹750 में 25% लाभ। लागत मूल्य?","opts":["₹550","₹600","₹650","₹560"],"ans":1,"exp":"CP = 750×100/125 = ₹600","diff":"easy"},
  {"qe":"Find the value of sin 30° + cos 60° + tan 45°?","qh":"sin 30° + cos 60° + tan 45° = ?","opts":["1","2","1.5","2.5"],"ans":1,"exp":"sin30°=0.5, cos60°=0.5, tan45°=1 → 0.5+0.5+1=2","diff":"medium"},
  {"qe":"A mixture of milk and water is in 4:1 ratio. If 10L water added, ratio becomes 2:1. Find original milk?","qh":"दूध:पानी=4:1। 10L पानी मिलाने पर 2:1 हो जाता है। मूल दूध?","opts":["20 L","40 L","60 L","80 L"],"ans":1,"exp":"Let milk=4x, water=x. After: 4x/(x+10)=2/1 → 4x=2x+20 → x=10 → milk=40L","diff":"hard"},
  {"qe":"What is (a+b)² − (a−b)² equal to?","qh":"(a+b)² − (a−b)² = ?","opts":["4ab","2ab","a²−b²","4a²b²"],"ans":0,"exp":"(a+b)²=a²+2ab+b²; (a−b)²=a²−2ab+b²; Difference = 4ab","diff":"medium"},
  {"qe":"If principal = ₹2000, rate = 5% per annum, SI = ₹300. Find time?","qh":"P=₹2000, r=5%, SI=₹300। समय?","opts":["2 years","3 years","4 years","5 years"],"ans":1,"exp":"T = SI×100/(P×R) = 300×100/(2000×5) = 3 years","diff":"easy"},
  {"qe":"A tank is 75% full. 45 litres taken out leaves it 60% full. Total capacity?","qh":"टैंक 75% भरा। 45L निकालने पर 60% रह जाता है। कुल क्षमता?","opts":["200 L","250 L","300 L","350 L"],"ans":2,"exp":"15% = 45L → 100% = 300L","diff":"medium"},
  {"qe":"The sum of interior angles of a hexagon?","qh":"षट्भुज के सभी आंतरिक कोणों का योग?","opts":["540°","720°","900°","1080°"],"ans":1,"exp":"Sum = (n−2)×180 = 4×180 = 720°","diff":"medium"},
  {"qe":"Find the HCF of 132 and 198?","qh":"132 और 198 का HCF?","opts":["22","33","44","66"],"ans":3,"exp":"132=4×33; 198=3×66; HCF=66","diff":"medium"},
  {"qe":"A train covers 450 km at uniform speed. If speed is 15 km/h more, time saved = 2h. Original speed?","qh":"ट्रेन 450 km। 15 km/h अधिक गति से 2 घंटे की बचत। मूल गति?","opts":["45 km/h","60 km/h","75 km/h","90 km/h"],"ans":0,"exp":"450/v − 450/(v+15) = 2 → solve: v=45 km/h","diff":"hard"},
  {"qe":"Volume of a cylinder: radius = 7 cm, height = 10 cm (π=22/7)?","qh":"बेलन: r=7 cm, h=10 cm का आयतन? (π=22/7)","opts":["1540 cm³","1440 cm³","1240 cm³","1640 cm³"],"ans":0,"exp":"V = πr²h = 22/7 × 49 × 10 = 1540 cm³","diff":"medium"},
  {"qe":"Simplify: 3/4 + 5/6 − 1/12?","qh":"3/4 + 5/6 − 1/12 = ?","opts":["1","3/2","19/12","5/4"],"ans":1,"exp":"LCM=12: 9/12+10/12−1/12=18/12=3/2","diff":"medium"},
  {"qe":"If 12 men can do a work in 20 days, how many days for 16 men?","qh":"12 आदमी 20 दिन में। 16 आदमी कितने दिन में?","opts":["12 days","14 days","15 days","18 days"],"ans":2,"exp":"12×20=16×d → d=240/16=15 days","diff":"easy"},
  {"qe":"Profit % when CP=₹450 and SP=₹540?","qh":"CP=₹450, SP=₹540 तो लाभ%?","opts":["15%","20%","25%","18%"],"ans":1,"exp":"Profit%=(90/450)×100=20%","diff":"easy"},
